script:
export const meta = { name: 'camiel-roadmap-status', description: 'Exhaustive fan-out to surface the full roadmap status of Project-Camiel', phases: [{ title: 'Local inventory' }, { title: 'Git context' }, { title: 'External sources' }, { title: 'Synthesis' }] };

const searchPaths = [
  '/Volumes/T9/Code/projects/Project-Camiel',
  '/Volumes/T9/Code/projects/athena',
];

const roadmapFiles = [
  'ROADMAP.md', 'roadmap.md', 'TODO.md', 'todo.md', 'CHANGELOG.md',
  'changelog.md', 'NEXT.md', 'next.md', 'PLANNED.md', 'PLAN.md', 'PLAN',
  '.github', 'gitlab', '.gitlab', '.roadmap', 'ROADMAP',
];

const gitFiles = [
  'CHANGELOG', 'CHANGELOG.md', 'TODO', 'TODO.md', 'NEXT', 'NEXT.md',
  'PLAN', 'PLAN.md', 'ROADMAP', 'ROADMAP.md',
];

phase('Local inventory');

// Fan out: read all possible roadmap/project-doc paths across both clones
const localDocs = await parallel([
  () => agent(`Look for any roadmap, changelog, todo, planned-features, or project-board files under ${searchPaths.join(' and ')}. Check: ROADMAP.md, TODO.md, CHANGELOG.md, .github/, .gitlab/, docs/, .claude/, .roadmap/, and any markdown files in the root. Read every matching file verbatim. Also check package.json for version history or release notes. Return the full content of all findings plus the exact paths.`, { label: 'roadmap-local-docs', tier: 'small' }),
  () => agent(`Check the Next.js app UI of Project-Camiel for any roadmap, status, or public-facing feature-announcement pages. The app is a Next.js project — check src/app/ for any route like /roadmap, /changelog, /status, /blog, /news, /whats-new. Also check public/ and src/components/ for any roadmap UI components. Return paths and content.`, { label: 'roadmap-ui-pages', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' }),
]);

// Also check the claude.md for any roadmap mentions
const claudeMd = await parallel(searchPaths.map(p => () => agent(`Read ${p}/.claude/CLAUDE.md and ${p}/CLAUDE.md (if exists) and search for any mentions of: roadmap, planned, TODO, upcoming, next, Q1, Q2, Q3, Q4, release, milestone. Return all relevant paragraphs verbatim.`, { label: `claude-md-${p.split('/').pop()}`, tier: 'small', cwd: p })));

phase('Git context');

const gitBranches = await parallel([
  () => agent(`Run: cd /Volumes/T9/Code/projects/Project-Camiel && git branch -a && git tag -l && git log --oneline -30`, { label: 'camiel-git-branches', tier: 'small' }),
  () => agent(`Run: cd /Volumes/T9/Code/projects/athena && git branch -a && git tag -l && git log --oneline -30 2>/dev/null || echo "No athena git found"`, { label: 'athena-git-branches', tier: 'small' }),
  () => agent(`Check for any GitLab project boards, milestones, or issues at git.euraika.net for a project named camiel, athena, vane, or Project-Camiel. Check: git.euraika.net/euraika/camiel, git.euraika.net/euraika/athena, git.euraika.net/euraika/Project-Camiel. Run: glab project list --mine 2>/dev/null; glab issue list --milestone 2>/dev/null; glab milestone list 2>/dev/null. Also check if there's a gitlab-ci.yml that references deploy stages or feature flags.`, { label: 'gitlab-roadmap', tier: 'small' }),
]);

// Check git remote for project tracking
const gitRemote = await parallel([
  () => agent(`Run in /Volumes/T9/Code/projects/Project-Camiel: git remote -v && cat .git/config`, { label: 'camiel-git-remote', tier: 'small' }),
]);

phase('External sources');

const external = await parallel([
  () => agent(`Search the web for "Project Camiel", "Camiel AI", "athena euraika", "vane ai euraika" for any public roadmap, blog post, tweet, or newsletter announcing the roadmap or upcoming features. Check git.euraika.net if accessible. Look for: changelog blog posts, tweet threads, LinkedIn announcements. Return URLs and key content.`, { label: 'web-roadmap-search', tier: 'small' }),
  () => agent(`If there is a deployed instance of Project-Camiel (check .env, docker-compose, docker-compose.yml, docker/, . Deployment*, *deployment*, k8s/, helm/, or similar for any URL or host), check the running app for a /changelog, /roadmap, or /status page. Also check if the app has a built-in "What's New" modal or banner. Return URLs checked and findings.`, { label: 'deployed-instance-check', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' }),
]);

// Also check package.json scripts for any release/version mgmt hints
const packageCheck = await parallel([
  () => agent(`Read /Volumes/T9/Code/projects/Project-Camiel/package.json fully (all fields including scripts, dependencies, version, description). Check for: "release", "version", "bump", "changelog", "publish", or anything referencing a deployment pipeline. Also check if there's a .release.json, version.txt, or similar.`, { label: 'package-json-check', tier: 'small' }),
]);

phase('Synthesis');

const synthesis = await agent(`
You are the synthesizer. Given the raw findings below, produce a structured "Roadmap Status Report" for Project-Camiel.

Organize your response as:

## 📋 Roadmap Status — Project-Camiel

### Version & Release Stage
What version is currently on main/develop? Is there a latest tag? What does the CHANGELOG say?

### 📌 Planned / In-Progress Features
List all features that appear planned, in-progress, or announced. Classify each as:
- ✅ Shipped (in code/changelog)
- 🚧 In Progress (on a feature branch or mentioned in recent commits)
- 📋 Announced (roadmap/doc mentions it but not started)
- ❓ Unknown / Unclear

### 🔒 Locked / Blocked
Anything explicitly blocked, deferred, or "do not touch"?

### 📡 External Signals
What do GitLab issues, milestones, project boards, or public announcements say?

### ⚠️ Gaps & Clarification Needed
What is NOT clear from any source? What does the developer need to answer?

Be honest about unknowns. If no roadmap exists anywhere, say so clearly.

--- FINDINGS ---
Local docs: ${JSON.stringify(localDocs.map(r => r?.slice(0, 3000)))}
Git branches: ${JSON.stringify(gitBranches.map(r => r?.slice(0, 2000)))}
External: ${JSON.stringify(external.map(r => r?.slice(0, 2000)))}
Package: ${JSON.stringify(packageCheck.map(r => r?.slice(0, 2000)))}
CLAUDE MD: ${JSON.stringify(claudeMd.map(r => r?.slice(0, 2000)))}
`, { label: 'roadmap-synthesis', tier: 'big' });

return {
  ok: true,
  version: '1.0',
  localDocsCount: localDocs.filter(Boolean).length,
  gitBranchesCount: gitBranches.filter(Boolean).length,
  externalCount: external.filter(Boolean).length,
  synthesis: synthesis,
};
